void propagate_block(block_t *block) {
 // Send block to all connected peers
 for (int i = 0; i < num_peers; i++) {
 send_block(block, peers[i]);
 }
}

void send_block(block_t *block, peer_t *peer) {
 // Send block to peer
 write(peer->sock, block, sizeof(block_t));
}
